namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatingPoints { get; set; }
    public int RatingCount { get; set; }

    public double AverageRating => RatingCount > 0 ? (double)TotalRatingPoints / RatingCount : 0;
}

public class RecipeCategory
{
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public string Icon { get; set; } = string.Empty;
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple and delicious pizza with fresh mozzarella and basil.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = [
                    "Preheat oven to 475°F (245°C) with a pizza stone.",
                    "Stretch dough into a 12-inch round.",
                    "Spread crushed tomatoes over the dough.",
                    "Tear mozzarella and distribute evenly.",
                    "Bake for 10–12 minutes until crust is golden.",
                    "Top with fresh basil and a drizzle of olive oil."
                ],
                TotalRatingPoints = 14, RatingCount = 3
            },
            new Recipe
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Creamy Roman pasta made with eggs, cheese, and pancetta.",
                Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper"],
                Steps = [
                    "Cook spaghetti in salted boiling water until al dente.",
                    "Crisp pancetta in a skillet over medium heat.",
                    "Whisk eggs with grated Pecorino and pepper.",
                    "Toss hot pasta with pancetta, then remove from heat.",
                    "Quickly stir in the egg mixture to create a creamy sauce.",
                    "Serve immediately with extra cheese and pepper."
                ],
                TotalRatingPoints = 9, RatingCount = 2
            },
            new Recipe
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken in a rich, spiced tomato-cream sauce.",
                Ingredients = ["Chicken thighs", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger"],
                Steps = [
                    "Marinate chicken in yogurt and spices for at least 1 hour.",
                    "Grill or broil chicken until charred.",
                    "Sauté onion, garlic, and ginger until softened.",
                    "Add tomato sauce and simmer for 15 minutes.",
                    "Stir in cream and garam masala.",
                    "Add chicken pieces and simmer 10 more minutes."
                ],
                TotalRatingPoints = 5, RatingCount = 1
            },
            new Recipe
            {
                Id = 4, Title = "Vegetable Pad Thai", Category = "Asian",
                Description = "A tangy, sweet stir-fried noodle dish loaded with vegetables.",
                Ingredients = ["Rice noodles", "Tofu", "Bean sprouts", "Peanuts", "Lime", "Tamarind paste", "Fish sauce", "Sugar", "Garlic"],
                Steps = [
                    "Soak rice noodles in warm water for 30 minutes, then drain.",
                    "Press and cube tofu, then pan-fry until golden.",
                    "Mix tamarind paste, fish sauce, and sugar for the sauce.",
                    "Stir-fry garlic, then add noodles and sauce.",
                    "Toss in tofu and bean sprouts.",
                    "Serve with crushed peanuts and lime wedges."
                ],
                TotalRatingPoints = 8, RatingCount = 2
            },
            new Recipe
            {
                Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Description = "Seasoned ground beef in warm tortillas with fresh toppings.",
                Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
                Steps = [
                    "Brown ground beef in a skillet over medium-high heat.",
                    "Add taco seasoning and water, simmer until thickened.",
                    "Warm tortillas in a dry skillet or microwave.",
                    "Fill tortillas with beef.",
                    "Top with lettuce, tomato, cheese, sour cream, and salsa."
                ],
                TotalRatingPoints = 12, RatingCount = 3
            },
            new Recipe
            {
                Id = 6, Title = "Chocolate Lava Cake", Category = "Desserts",
                Description = "Rich chocolate cakes with a molten center.",
                Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract"],
                Steps = [
                    "Preheat oven to 425°F (220°C). Butter and flour ramekins.",
                    "Melt chocolate and butter together.",
                    "Whisk eggs, sugar, and vanilla until thick.",
                    "Fold chocolate mixture into eggs, then fold in flour.",
                    "Pour into ramekins and bake 12–14 minutes.",
                    "Invert onto plates and serve immediately."
                ],
                TotalRatingPoints = 10, RatingCount = 2
            }
        ];
        _nextId = 7;
    }

    public List<RecipeCategory> GetCategories() =>
    [
        new() { Name = "Italian", Description = "Pasta, pizza, and Mediterranean classics", Icon = "🍝" },
        new() { Name = "Indian", Description = "Aromatic curries and vibrant spices", Icon = "🍛" },
        new() { Name = "Asian", Description = "Stir-fries, noodles, and umami flavors", Icon = "🥢" },
        new() { Name = "Mexican", Description = "Bold flavors with chilies and lime", Icon = "🌮" },
        new() { Name = "Desserts", Description = "Sweet treats and baked delights", Icon = "🍰" }
    ];

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetRecipeById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatingPoints += stars;
            recipe.RatingCount++;
        }
    }

    public Recipe AddRecipe(string title, string category, string ingredients, string steps)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            Description = $"A community-submitted {category.ToLower()} recipe.",
            Ingredients = ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList()
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

