@page "/category/{CategoryName}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes — RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@{
    var recipes = RecipeService.GetRecipesByCategory(CategoryName ?? "");
}

@if (recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category yet. <a href="/submit">Be the first to submit one!</a></div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 g-4">
        @foreach (var recipe in recipes)
        {
            <div class="col">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text text-muted">@recipe.Description</p>
                        <p class="mb-2">
                            @for (int i = 1; i <= 5; i++)
                            {
                                <span>@(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")</span>
                            }
                            <small class="text-muted ms-1">(@recipe.RatingCount ratings)</small>
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-primary btn-sm">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string? CategoryName { get; set; }
}

@page "/recipe/{RecipeId:int}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") — RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        @if (recipe is not null)
        {
            <li class="breadcrumb-item"><a href="/category/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        }
    </ol>
</nav>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <h1>@recipe.Title</h1>
    <p class="lead text-muted">@recipe.Description</p>

    <div class="row mt-4">
        <div class="col-md-4">
            <div class="card mb-4">
                <div class="card-header"><strong>Ingredients</strong></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>

        <div class="col-md-8">
            <h3>Steps</h3>
            <ol class="list-group list-group-numbered mb-4">
                @foreach (var step in recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>

    <div class="card mt-2 mb-4">
        <div class="card-body">
            <h5 class="card-title">Rate this Recipe</h5>
            <StarRating RecipeId="recipe.Id" CurrentAverage="recipe.AverageRating" RatingCount="recipe.RatingCount" />
        </div>
    </div>
}

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private RecipeShare.Models.Recipe? recipe;

    protected override void OnInitialized()
    {
        recipe = RecipeService.GetRecipeById(RecipeId);
    }
}

@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService

<div>
    <span class="me-2" style="font-size: 1.5rem; cursor: pointer;" @onmouseleave="() => hoverRating = 0">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span role="button"
                  @onclick="() => SubmitRating(star)"
                  @onmouseenter="() => hoverRating = star"
                  style="color: @(star <= DisplayRating ? "gold" : "#ccc");">★</span>
        }
    </span>

    @if (submitted)
    {
        <span class="text-success">✓ Thanks for rating!</span>
    }
    else
    {
        <span class="text-muted">@currentAverage.ToString("0.0") avg (@currentCount ratings)</span>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public int RecipeId { get; set; }

    [Parameter]
    public double CurrentAverage { get; set; }

    [Parameter]
    public int RatingCount { get; set; }

    private int hoverRating;
    private int selectedRating;
    private bool submitted;
    private double currentAverage;
    private int currentCount;

    private int DisplayRating => hoverRating > 0 ? hoverRating : selectedRating;

    protected override void OnInitialized()
    {
        currentAverage = CurrentAverage;
        currentCount = RatingCount;
    }

    private void SubmitRating(int stars)
    {
        if (submitted) return;

        RecipeService.AddRating(RecipeId, stars);
        selectedRating = stars;
        submitted = true;

        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            currentAverage = recipe.AverageRating;
            currentCount = recipe.RatingCount;
        }
    }
}

