<div>
    <span class="me-2" style="font-size: 1.5rem; cursor: pointer;" @onmouseleave="() => hoverRating = 0">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span role="button"
                  @onclick="() => SubmitRating(star)"
                  @onmouseenter="() => hoverRating = star"
                  style="color: @(star <= DisplayRating ? "gold" : "#ccc");">★</span>
        }
    </span>

    @if (submitted)
    {
        <span class="text-success">✓ Thanks for rating!</span>
    }
    else
    {
        <span class="text-muted">@currentAverage.ToString("0.0") avg (@currentCount ratings)</span>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public int RecipeId { get; set; }

    [Parameter]
    public double CurrentAverage { get; set; }

    [Parameter]
    public int RatingCount { get; set; }

    private int hoverRating;
    private int selectedRating;
    private bool submitted;
    private double currentAverage;
    private int currentCount;

    private int DisplayRating => hoverRating > 0 ? hoverRating : selectedRating;

    protected override void OnInitialized()
    {
        currentAverage = CurrentAverage;
        currentCount = RatingCount;
    }

    private void SubmitRating(int stars)
    {
        if (submitted) return;

        RecipeService.AddRating(RecipeId, stars);
        selectedRating = stars;
        submitted = true;

        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            currentAverage = recipe.AverageRating;
            currentCount = recipe.RatingCount;
        }
    }
}
