    <div class="mb-3">
        <label for="steps" class="form-label">Steps</label>
        <InputTextArea id="steps" @bind-Value="model.Steps" class="form-control" rows="5"
                       placeholder="One step per line" />
        <ValidationMessage For="() => model.Steps" class="text-danger" />
    </div>

    <button type="submit" class="btn btn-success">Submit Recipe</button>
</EditForm>

@code {
    private RecipeFormModel model = new();

    private void HandleSubmit()
    {
        var recipe = RecipeService.AddRecipe(model.Title, model.Category, model.Ingredients, model.Steps);
        Nav.NavigateTo($"/recipe/{recipe.Id}");
    }

    private sealed class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please enter a recipe title.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please list at least one ingredient.")]
        public string Ingredients { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please describe at least one step.")]
        public string Steps { get; set; } = "";
    }
}
